8,0.04037370,-0.00780567,-0.00514684,-0.04133607,-0.01171277,0.03480155,-0.00840677,-0.01462055,-0.00548292,0.10069545,-0.00917907,0.07607078,-0.00722789,-0.02076002,-0.01097962,0.02282129,-0.02869717,-0.10558961,0.05586192,-0.05169908,-0.02011006,0.06261517,-0.04521777,-0.03221672,0.02807768,-0.02779954,-0.01300900,0.01899375,-0.03573954,-0.04210291,0.00164662,0.01788246,-0.01793310,-0.01645432,-0.02379849,-0.07054094,0.00017792,0.02015705,0.07074299,0.03259514,-0.01067221,0.00651500]',E'Scoped routes\n\n```elixir\ndefmodule HelloWeb.Router do\n  use Phoenix.Router\n  ...\n  scope "/", HelloWeb do\n    pipe_through :browser\n\n    resources "/users", UserController\n  end\n\n  scope "/", AnotherAppWeb do\n    pipe_through :browser\n\n    resources "/posts", PostController\n  end\n  ...\nend\n```\n\nIf we do duplicate a route — which means two routes having the same path — we''ll get this familiar warning:\n\n```console\nwarning: this clause cannot match because a previous clause at line 16 always matches\n```','{"source": "phoenix", "version": "1.7", "language": "elixir", "title": "Routing", "section_title": "routing", "url": "https://github.com/phoenixframework/phoenix/blob/main/guides/routing.md", "topics": "phoenix,elixir,routing", "categories": "web,elixir,fullstack,realtime"}');
