453,0.05519809,-0.02324974,-0.00567543,-0.01797763,0.00579111,0.06899211,0.01114483,0.03863191,0.00263848,0.02833756,-0.00978756,0.03753429,0.03614492,-0.02155365,-0.02856470,-0.03419363,-0.02057668,-0.04592773,0.03904167,-0.01092566,-0.00033610,-0.00844714,-0.07702358,-0.00776497,-0.00692618,-0.01593722,-0.00781964,0.01298823,0.00017887,0.00641390,-0.00062878,0.05903606,0.06941558,0.06884050,-0.02050891,-0.04599126,0.02198200,0.00831833,-0.01174614,0.08072315,0.03070709,0.04016317]',E'Creating new pipelines\n\npipeline :browser do\n    plug :accepts, ["html"]\n    plug :fetch_session\n    plug :fetch_live_flash\n    plug :put_root_layout, html: {HelloWeb.Layouts, :root}\n    plug :protect_from_forgery\n    plug :put_secure_browser_headers\n  end\n\n  pipeline :auth do\n    plug HelloWeb.Authentication\n  end\n\n  scope "/reviews", HelloWeb do\n    pipe_through [:browser, :auth]\n\n    resources "/", ReviewController\n  end\nend\n```','{"source": "phoenix", "version": "1.7", "language": "elixir", "title": "Routing", "section_title": "routing", "url": "https://github.com/phoenixframework/phoenix/blob/main/guides/routing.md", "topics": "phoenix,elixir,routing", "categories": "web,elixir,fullstack,realtime"}');
